fun solve(points: Array<Array<Long>>): Long {
    val MOD = 10_000_000_07L
    val yMap = mutableMapOf<Long, MutableList<Long>>()

    // Group points by their y-coordinate
    for (point in points) {
        val y = point[1]
        if (!yMap.containsKey(y)) {
            yMap[y] = mutableListOf()
        }
        yMap[y]!!.add(point[0])
    }

    val yKeys = yMap.keys.toList()
    val result = mutableListOf<Long>()

    // For each pair of y-coordinates, calculate the number of horizontal lines
    for (i in yKeys.indices) {
        for (j in i + 1 until yKeys.size) {
            val y1 = yKeys[i]
            val y2 = yKeys[j]
            val x1s = yMap[y1]!!
            val x2s = yMap[y2]!!

            // Count the number of horizontal lines between the two y-levels
            val count = x1s.size.toLong() * x2s.size.toLong()
            result.add(count)
        }
    }

    // Calculate the total number of horizontal trapezoids
    var total = 0L
    for (count in result) {
        total = (total + count) % MOD
    }

    return total
}
